impl PtyKillArgs {
    fn resolved_session_ids(&self) -> Result<Vec<u64>> {
        let mut ids = Vec::new();
        if let Some(session_id) = self.session_id {
            ids.push(session_id);
        }
        ids.extend(self.session_ids.iter().copied());
        if ids.is_empty()
            && let Ok(session_id) = resolve_pty_session_selector(
                self.session_id,
                self.pid,
                self.name.as_deref(),
                "pty_kill",
            )
        {
            ids.push(session_id);
        }
        ids.sort_unstable();
        ids.dedup();
        if ids.is_empty() {
            Err(anyhow!(
                "pty_kill 需要 session_id / session_ids / pid / name"
            ))
        } else {
            Ok(ids)
        }
    }
}

fn resolve_pty_session_selector(
    session_id: Option<u64>,
    pid: Option<i32>,
    name: Option<&str>,
    tool_name: &str,
) -> Result<u64> {
    terminal::resolve_session_selector(session_id, pid, name).with_context(|| {
        let mut selectors = Vec::new();
        if let Some(session_id) = session_id {
            selectors.push(format!("session_id={session_id}"));
        }
        if let Some(pid) = pid {
            selectors.push(format!("pid={pid}"));
        }
        if let Some(name) = name.map(str::trim).filter(|value| !value.is_empty()) {
            selectors.push(format!("name={name}"));
        }
        if selectors.is_empty() {
            format!("{tool_name} 需要 session_id / pid / name")
        } else {
            format!("{tool_name} 无法定位 PTY 会话：{}", selectors.join(" · "))
        }
    })
}

impl SingleAgentArgs {
    fn resolved_ids(&self) -> Result<Vec<String>> {
        let mut ids = Vec::new();
        if let Some(id) = self
            .id
            .as_deref()
            .map(str::trim)
            .filter(|value| !value.is_empty())
        {
            ids.push(id.to_string());
        }
        ids.extend(
            self.ids
                .iter()
                .map(|id| id.trim())
                .filter(|id| !id.is_empty())
                .map(str::to_string),
        );
        ids.sort();
        ids.dedup();
        if ids.is_empty() {
            Err(anyhow!("agent 参数不能为空"))
        } else {
            Ok(ids)
        }
    }
}

