            assert!(role_read.output_preview.contains("动态角色治理链路"));

            let coding_read = execute_memory_read(
                json!({
                    "target": "datememory",
                    "persona": "coding",
                    "date": "2026-03-22"
                })
                .to_string()
                .as_str(),
            )
            .expect("memory read coding");
